export const viewBox = "0 0 1000 387.2";

// Projektions-Bounds (für Pin-Positionen identisch zur Karte).
export const bounds = { latT: 83.0, latB: -56.0, lonL: -169.0, lonR: 190.0 } as const;

/** lon/lat -> Punkt im viewBox-Koordinatensystem. */
export function project(lon: number, lat: number): { x: number; y: number } {
  return {
    x: ((lon - bounds.lonL) / (bounds.lonR - bounds.lonL)) * 1000,
    y: ((bounds.latT - lat) / (bounds.latT - bounds.latB)) * 387.2,
  };
}

